class DriverDashboardScreen extends ConsumerStatefulWidget {\n  const DriverDashboardScreen({super.key});\n  \n  @override\n  ConsumerState<DriverDashboardScreen> createState() => _DriverDashboardScreenState();\n}\n\nclass _DriverDashboardScreenState extends ConsumerState<DriverDashboardScreen> \n    with TickerProviderStateMixin {\n  \n  late TabController _tabController;\n  GoogleMapController? _mapController;\n  StreamSubscription<Position>? _positionStream;\n  \n  Timer? _refreshTimer;\n  bool _showHeatMap = false;\n  bool _isLocationEnabled = false;\n  LatLng? _currentLocation;\n  \n  final Set<Marker> _markers = {};\n  final Set<Circle> _circles = {};\n  \n  @override\n  void initState() {\n    super.initState();\n    _tabController = TabController(length: 3, vsync: this);\n    _initializeDriver();\n    _startLocationTracking();\n    _startRefreshTimer();\n  }\n  \n  @override\n  void dispose() {\n    _tabController.dispose();\n    _positionStream?.cancel();\n    _refreshTimer?.cancel();\n    _mapController?.dispose();\n    super.dispose();\n  }\n  \n  void _initializeDriver() {\n    WidgetsBinding.instance.addPostFrameCallback((_) {\n      // Inicializar providers\n      ref.read(driverStatusProvider.notifier).loadStatus();\n      ref.read(driverEarningsProvider.notifier).loadTodayEarnings();\n      ref.read(rideRequestsProvider.notifier).startListening();\n    });\n  }\n  \n  void _startLocationTracking() async {\n    try {\n      final permission = await Geolocator.checkPermission();\n      if (permission == LocationPermission.denied) {\n        final requestedPermission = await Geolocator.requestPermission();\n        if (requestedPermission == LocationPermission.denied) {\n          return;\n        }\n      }\n      \n      setState(() {\n        _isLocationEnabled = true;\n      });\n      \n      _positionStream = Geolocator.getPositionStream(\n        locationSettings: const LocationSettings(\n          accuracy: LocationAccuracy.high,\n          distanceFilter: 10, // Actualizar cada 10 metros\n        ),\n      ).listen((position) {\n        final newLocation = LatLng(position.latitude, position.longitude);\n        setState(() {\n          _currentLocation = newLocation;\n        });\n        \n        // Actualizar ubicación del conductor\n        ref.read(driverStatusProvider.notifier)\n          .updateLocation(position.latitude, position.longitude, position.heading);\n        \n        // Centrar mapa en la nueva ubicación si está online\n        final status = ref.read(driverStatusProvider).value;\n        if (status?.isOnline == true && _mapController != null) {\n          _mapController!.animateCamera(\n            CameraUpdate.newLatLng(newLocation),\n          );\n        }\n      });\n    } catch (e) {\n      if (kDebugMode) {
        Logger().error('Error starting location tracking', error: e);
      }\n    }\n  }\n  \n  void _startRefreshTimer() {\n    _refreshTimer = Timer.periodic(const Duration(seconds: 30), (_) {\n      if (mounted) {\n        // Refrescar datos cada 30 segundos\n        ref.read(driverEarningsProvider.notifier).loadTodayEarnings();\n        ref.read(rideRequestsProvider.notifier).refreshRequests();\n      }\n    });\n  }\n  \n  @override\n  Widget build(BuildContext context) {\n    return Scaffold(\n      body: SafeArea(\n        child: Column(\n          children: [\n            _buildHeader(),\n            _buildTabBar(),\n            Expanded(\n              child: TabBarView(\n                controller: _tabController,\n                children: [\n                  _buildMapTab(),\n                  _buildEarningsTab(),\n                  _buildHistoryTab(),\n                ],\n              ),\n            ),\n          ],\n        ),\n      ),\n      floatingActionButton: _buildFloatingActionButton(),\n    );\n  }\n  \n  Widget _buildHeader() {\n    final driverStatus = ref.watch(driverStatusProvider);\n    final todayEarnings = ref.watch(driverEarningsProvider);\n    \n    return Container(\n      padding: const EdgeInsets.all(16),\n      decoration: BoxDecoration(\n        gradient: LinearGradient(\n          colors: [\n            AppColors.primary,\n            AppColors.primary.withOpacity(0.8),\n          ],\n          begin: Alignment.topLeft,\n          end: Alignment.bottomRight,\n        ),\n        boxShadow: [\n          BoxShadow(\n            color: AppColors.primary.withOpacity(0.3),\n            blurRadius: 10,\n            offset: const Offset(0, 5),\n          ),\n        ],\n      ),\n      child: Column(\n        children: [\n          // Header principal\n          Row(\n            children: [\n              // Avatar y información del conductor\n              driverStatus.when(\n                data: (status) => CircleAvatar(\n                  radius: 24,\n                  backgroundImage: status.profilePhoto != null\n                    ? CachedNetworkImageProvider(status.profilePhoto!)\n                    : null,\n                  child: status.profilePhoto == null\n                    ? const Icon(Icons.person, color: Colors.white)\n                    : null,\n                ),\n                loading: () => const CircleAvatar(\n                  radius: 24,\n                  child: CircularProgressIndicator(strokeWidth: 2),\n                ),\n                error: (_, __) => const CircleAvatar(\n                  radius: 24,\n                  child: Icon(Icons.error),\n                ),\n              ),\n              \n              const SizedBox(width: 12),\n              \n              Expanded(\n                child: Column(\n                  crossAxisAlignment: CrossAxisAlignment.start,\n                  children: [\n                    driverStatus.when(\n                      data: (status) => Text(\n                        'Hola, ${status.name}',\n                        style: const TextStyle(\n                          color: Colors.white,\n                          fontSize: 18,\n                          fontWeight: FontWeight.bold,\n                        ),\n                      ),\n                      loading: () => Container(\n                        width: 120,\n                        height: 18,\n                        decoration: BoxDecoration(\n                          color: Colors.white.withOpacity(0.3),\n                          borderRadius: BorderRadius.circular(4),\n                        ),\n                      ),\n                      error: (_, __) => const Text(\n                        'Error al cargar',\n                        style: TextStyle(color: Colors.white),\n                      ),\n                    ),\n                    \n                    const SizedBox(height: 4),\n                    \n                    Row(\n                      children: [\n                        driverStatus.when(\n                          data: (status) => Container(\n                            padding: const EdgeInsets.symmetric(\n                              horizontal: 8,\n                              vertical: 2,\n                            ),\n                            decoration: BoxDecoration(\n                              color: status.isOnline\n                                ? Colors.green\n                                : Colors.grey[600],\n                              borderRadius: BorderRadius.circular(12),\n                            ),\n                            child: Text(\n                              status.isOnline ? 'En línea' : 'Desconectado',\n                              style: const TextStyle(\n                                color: Colors.white,\n                                fontSize: 12,\n                                fontWeight: FontWeight.w500,\n                              ),\n                            ),\n                          ),\n                          loading: () => Container(\n                            width: 80,\n                            height: 16,\n                            decoration: BoxDecoration(\n                              color: Colors.white.withOpacity(0.3),\n                              borderRadius: BorderRadius.circular(8),\n                            ),\n                          ),\n                          error: (_, __) => Container(\n                            padding: const EdgeInsets.symmetric(\n                              horizontal: 8,\n                              vertical: 2,\n                            ),\n                            decoration: BoxDecoration(\n                              color: Colors.red,\n                              borderRadius: BorderRadius.circular(12),\n                            ),\n                            child: const Text(\n                              'Error',\n                              style: TextStyle(\n                                color: Colors.white,\n                                fontSize: 12,\n                              ),\n                            ),\n                          ),\n                        ),\n                        \n                        const SizedBox(width: 8),\n                        \n                        // Timer de tiempo online\n                        driverStatus.when(\n                          data: (status) => status.isOnline\n                            ? OnlineTimerWidget(startTime: status.onlineStartTime!)\n                            : const SizedBox.shrink(),\n                          loading: () => const SizedBox.shrink(),\n                          error: (_, __) => const SizedBox.shrink(),\n                        ),\n                      ],\n                    ),\n                  ],\n                ),\n              ),\n              \n              // Notificaciones\n              NotificationBadge(\n                count: ref.watch(rideRequestsProvider).value?.length ?? 0,\n                child: IconButton(\n                  onPressed: _openNotifications,\n                  icon: const Icon(\n                    Icons.notifications_outlined,\n                    color: Colors.white,\n                  ),\n                ),\n              ),\n              \n              // Menú\n              IconButton(\n                onPressed: _openMenu,\n                icon: const Icon(\n                  Icons.menu,\n                  color: Colors.white,\n                ),\n              ),\n            ],\n          ),\n          \n          const SizedBox(height: 16),\n          \n          // Resumen de ganancias del día\n          Row(\n            children: [\n              Expanded(\n                child: _buildEarningsSummaryCard(\n                  'Ganancias Hoy',\n                  todayEarnings.when(\n                    data: (earnings) => Formatters.formatCurrency(earnings.totalEarnings),\n                    loading: () => '---',\n                    error: (_, __) => 'Error',\n                  ),\n                  Icons.monetization_on,\n                  Colors.green,\n                ),\n              ),\n              \n              const SizedBox(width: 12),\n              \n              Expanded(\n                child: _buildEarningsSummaryCard(\n                  'Viajes Hoy',\n                  todayEarnings.when(\n                    data: (earnings) => earnings.totalTrips.toString(),\n                    loading: () => '---',\n                    error: (_, __) => '0',\n                  ),\n                  Icons.local_taxi,\n                  Colors.blue,\n                ),\n              ),\n              \n              const SizedBox(width: 12),\n              \n              Expanded(\n                child: _buildEarningsSummaryCard(\n                  'Calificación',\n                  driverStatus.when(\n                    data: (status) => status.rating.toStringAsFixed(1),\n                    loading: () => '---',\n                    error: (_, __) => '0.0',\n                  ),\n                  Icons.star,\n                  Colors.amber,\n                ),\n              ),\n            ],\n          ),\n        ],\n      ),\n    );\n  }\n  \n  Widget _buildEarningsSummaryCard(\n    String title,\n    String value,\n    IconData icon,\n    Color color,\n  ) {\n    return Container(\n      padding: const EdgeInsets.all(12),\n      decoration: BoxDecoration(\n        color: Colors.white.withOpacity(0.15),\n        borderRadius: BorderRadius.circular(12),\n        border: Border.all(\n          color: Colors.white.withOpacity(0.3),\n        ),\n      ),\n      child: Column(\n        children: [\n          Icon(\n            icon,\n            color: color,\n            size: 20,\n          ),\n          const SizedBox(height: 4),\n          Text(\n            title,\n            style: TextStyle(\n              color: Colors.white.withOpacity(0.9),\n              fontSize: 10,\n            ),\n            textAlign: TextAlign.center,\n          ),\n          const SizedBox(height: 2),\n          Text(\n            value,\n            style: const TextStyle(\n              color: Colors.white,\n              fontSize: 14,\n              fontWeight: FontWeight.bold,\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n  \n  Widget _buildTabBar() {\n    return Container(\n      decoration: BoxDecoration(\n        color: Colors.white,\n        boxShadow: [\n          BoxShadow(\n            color: Colors.black.withOpacity(0.1),\n            blurRadius: 5,\n            offset: const Offset(0, 2),\n          ),\n        ],\n      ),\n      child: TabBar(\n        controller: _tabController,\n        labelColor: AppColors.primary,\n        unselectedLabelColor: Colors.grey[600],\n        indicatorColor: AppColors.primary,\n        tabs: const [\n          Tab(\n            icon: Icon(Icons.map),\n            text: 'Mapa',\n          ),\n          Tab(\n            icon: Icon(Icons.monetization_on),\n            text: 'Ganancias',\n          ),\n          Tab(\n            icon: Icon(Icons.history),\n            text: 'Historial',\n          ),\n        ],\n      ),\n    );\n  }\n  \n  Widget _buildMapTab() {\n    final driverStatus = ref.watch(driverStatusProvider);\n    final rideRequests = ref.watch(rideRequestsProvider);\n    \n    return Stack(\n      children: [\n        // Mapa\n        DriverMapWidget(\n          onMapCreated: (controller) {\n            _mapController = controller;\n          },\n          currentLocation: _currentLocation,\n          showHeatMap: _showHeatMap,\n          rideRequests: rideRequests.value ?? [],\n        ),\n        \n        // Controles del mapa\n        Positioned(\n          top: 16,\n          right: 16,\n          child: Column(\n            children: [\n              // Toggle heat map\n              Container(\n                decoration: BoxDecoration(\n                  color: Colors.white,\n                  borderRadius: BorderRadius.circular(8),\n                  boxShadow: [\n                    BoxShadow(\n                      color: Colors.black.withOpacity(0.1),\n                      blurRadius: 5,\n                      offset: const Offset(0, 2),\n                    ),\n                  ],\n                ),\n                child: IconButton(\n                  onPressed: () {\n                    setState(() {\n                      _showHeatMap = !_showHeatMap;\n                    });\n                  },\n                  icon: Icon(\n                    _showHeatMap ? Icons.layers_clear : Icons.layers,\n                    color: _showHeatMap ? AppColors.primary : Colors.grey[600],\n                  ),\n                ),\n              ),\n              \n              const SizedBox(height: 8),\n              \n              // Centrar en ubicación actual\n              Container(\n                decoration: BoxDecoration(\n                  color: Colors.white,\n                  borderRadius: BorderRadius.circular(8),\n                  boxShadow: [\n                    BoxShadow(\n                      color: Colors.black.withOpacity(0.1),\n                      blurRadius: 5,\n                      offset: const Offset(0, 2),\n                    ),\n                  ],\n                ),\n                child: IconButton(\n                  onPressed: _centerOnCurrentLocation,\n                  icon: const Icon(Icons.my_location),\n                ),\n              ),\n            ],\n          ),\n        ),\n        \n        // Panel de solicitudes de viaje\n        if (rideRequests.value?.isNotEmpty == true)\n          Positioned(\n            bottom: 16,\n            left: 16,\n            right: 16,\n            child: Container(\n              constraints: const BoxConstraints(maxHeight: 200),\n              child: ListView.builder(\n                scrollDirection: Axis.horizontal,\n                itemCount: rideRequests.value!.length,\n                itemBuilder: (context, index) {\n                  final request = rideRequests.value![index];\n                  return Container(\n                    width: MediaQuery.of(context).size.width - 64,\n                    margin: EdgeInsets.only(\n                      right: index < rideRequests.value!.length - 1 ? 12 : 0,\n                    ),\n                    child: RideRequestCard(\n                      request: request,\n                      onAccept: () => _acceptRideRequest(request),\n                      onReject: () => _rejectRideRequest(request),\n                      onViewDetails: () => _viewRequestDetails(request),\n                    ),\n                  );\n                },\n              ),\n            ).animate().slideY(\n              begin: 1,\n              duration: const Duration(milliseconds: 300),\n              curve: Curves.easeOutQuart,\n            ),\n          ),\n        \n        // Estado del conductor\n        Positioned(\n          bottom: rideRequests.value?.isNotEmpty == true ? 232 : 16,\n          left: 16,\n          child: driverStatus.when(\n            data: (status) => DriverStatusCard(\n              status: status,\n              onToggleOnline: _toggleOnlineStatus,\n            ),\n            loading: () => const CircularProgressIndicator(),\n            error: (_, __) => const SizedBox.shrink(),\n          ),\n        ),\n      ],\n    );\n  }\n  \n  Widget _buildEarningsTab() {\n    final earnings = ref.watch(driverEarningsProvider);\n    \n    return earnings.when(\n      data: (data) => SingleChildScrollView(\n        padding: const EdgeInsets.all(16),\n        child: Column(\n          crossAxisAlignment: CrossAxisAlignment.start,\n          children: [\n            // Resumen de ganancias\n            EarningsSummaryCard(\n              earnings: data,\n              onViewDetails: _viewEarningsDetails,\n            ),\n            \n            const SizedBox(height: 20),\n            \n            // Gráfico de ganancias\n            _buildEarningsChart(data),\n            \n            const SizedBox(height: 20),\n            \n            // Desglose por categorías\n            _buildEarningsBreakdown(data),\n            \n            const SizedBox(height: 20),\n            \n            // Metas y objetivos\n            _buildGoalsCard(data),\n          ],\n        ),\n      ),\n      loading: () => const Center(\n        child: CircularProgressIndicator(),\n      ),\n      error: (error, _) => Center(\n        child: Column(\n          mainAxisAlignment: MainAxisAlignment.center,\n          children: [\n            const Icon(\n              Icons.error_outline,\n              size: 64,\n              color: Colors.grey,\n            ),\n            const SizedBox(height: 16),\n            Text(\n              'Error al cargar ganancias: $error',\n              textAlign: TextAlign.center,\n            ),\n            const SizedBox(height: 16),\n            CustomButton(\n              text: 'Reintentar',\n              onPressed: () {\n                ref.read(driverEarningsProvider.notifier).loadTodayEarnings();\n              },\n            ),\n          ],\n        ),\n      ),\n    );\n  }\n  \n  Widget _buildHistoryTab() {\n    return const Center(\n      child: Text(\n        'Historial de viajes',\n        style: TextStyle(fontSize: 18),\n      ),\n    );\n  }\n  \n  Widget _buildEarningsChart(DriverEarnings earnings) {\n    return Container(\n      padding: const EdgeInsets.all(20),\n      decoration: BoxDecoration(\n        color: Colors.white,\n        borderRadius: BorderRadius.circular(16),\n        boxShadow: [\n          BoxShadow(\n            color: Colors.black.withOpacity(0.1),\n            blurRadius: 10,\n            offset: const Offset(0, 5),\n          ),\n        ],\n      ),\n      child: Column(\n        crossAxisAlignment: CrossAxisAlignment.start,\n        children: [\n          const Text(\n            'Ganancias de la semana',\n            style: TextStyle(\n              fontSize: 18,\n              fontWeight: FontWeight.bold,\n            ),\n          ),\n          const SizedBox(height: 20),\n          // Aquí iría un gráfico real como fl_chart\n          Container(\n            height: 200,\n            width: double.infinity,\n            decoration: BoxDecoration(\n              color: Colors.grey[100],\n              borderRadius: BorderRadius.circular(8),\n            ),\n            child: const Center(\n              child: Text(\n                'Gráfico de ganancias\\n(Implementar con fl_chart)',\n                textAlign: TextAlign.center,\n                style: TextStyle(\n                  color: Colors.grey,\n                ),\n              ),\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n  \n  Widget _buildEarningsBreakdown(DriverEarnings earnings) {\n    return Container(\n      padding: const EdgeInsets.all(20),\n      decoration: BoxDecoration(\n        color: Colors.white,\n        borderRadius: BorderRadius.circular(16),\n        boxShadow: [\n          BoxShadow(\n            color: Colors.black.withOpacity(0.1),\n            blurRadius: 10,\n            offset: const Offset(0, 5),\n          ),\n        ],\n      ),\n      child: Column(\n        crossAxisAlignment: CrossAxisAlignment.start,\n        children: [\n          const Text(\n            'Desglose de ganancias',\n            style: TextStyle(\n              fontSize: 18,\n              fontWeight: FontWeight.bold,\n            ),\n          ),\n          const SizedBox(height: 16),\n          \n          _buildEarningsRow(\n            'Viajes completados',\n            Formatters.formatCurrency(earnings.tripEarnings),\n            Colors.green,\n          ),\n          _buildEarningsRow(\n            'Propinas',\n            Formatters.formatCurrency(earnings.tips),\n            Colors.blue,\n          ),\n          _buildEarningsRow(\n            'Bonos',\n            Formatters.formatCurrency(earnings.bonuses),\n            Colors.orange,\n          ),\n          const Divider(),\n          _buildEarningsRow(\n            'Total',\n            Formatters.formatCurrency(earnings.totalEarnings),\n            AppColors.primary,\n            isTotal: true,\n          ),\n        ],\n      ),\n    );\n  }\n  \n  Widget _buildEarningsRow(\n    String label,\n    String amount,\n    Color color, {\n    bool isTotal = false,\n  }) {\n    return Padding(\n      padding: const EdgeInsets.symmetric(vertical: 8),\n      child: Row(\n        mainAxisAlignment: MainAxisAlignment.spaceBetween,\n        children: [\n          Text(\n            label,\n            style: TextStyle(\n              fontSize: isTotal ? 16 : 14,\n              fontWeight: isTotal ? FontWeight.bold : FontWeight.normal,\n            ),\n          ),\n          Text(\n            amount,\n            style: TextStyle(\n              fontSize: isTotal ? 16 : 14,\n              fontWeight: FontWeight.bold,\n              color: color,\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n  \n  Widget _buildGoalsCard(DriverEarnings earnings) {\n    const dailyGoal = 200.0; // Meta diaria\n    final progress = earnings.totalEarnings / dailyGoal;\n    \n    return Container(\n      padding: const EdgeInsets.all(20),\n      decoration: BoxDecoration(\n        color: Colors.white,\n        borderRadius: BorderRadius.circular(16),\n        boxShadow: [\n          BoxShadow(\n            color: Colors.black.withOpacity(0.1),\n            blurRadius: 10,\n            offset: const Offset(0, 5),\n          ),\n        ],\n      ),\n      child: Column(\n        crossAxisAlignment: CrossAxisAlignment.start,\n        children: [\n          Row(\n            mainAxisAlignment: MainAxisAlignment.spaceBetween,\n            children: [\n              const Text(\n                'Meta diaria',\n                style: TextStyle(\n                  fontSize: 18,\n                  fontWeight: FontWeight.bold,\n                ),\n              ),\n              Text(\n                '${(progress * 100).toStringAsFixed(0)}%',\n                style: TextStyle(\n                  fontSize: 16,\n                  fontWeight: FontWeight.bold,\n                  color: progress >= 1.0 ? Colors.green : AppColors.primary,\n                ),\n              ),\n            ],\n          ),\n          const SizedBox(height: 16),\n          \n          // Barra de progreso\n          LinearProgressIndicator(\n            value: progress.clamp(0.0, 1.0),\n            backgroundColor: Colors.grey[300],\n            valueColor: AlwaysStoppedAnimation<Color>(\n              progress >= 1.0 ? Colors.green : AppColors.primary,\n            ),\n          ),\n          \n          const SizedBox(height: 12),\n          \n          Text(\n            progress >= 1.0\n              ? '¡Felicidades! Has alcanzado tu meta diaria'\n              : 'Te faltan ${Formatters.formatCurrency(dailyGoal - earnings.totalEarnings)} para alcanzar tu meta',\n            style: TextStyle(\n              color: Colors.grey[600],\n              fontSize: 14,\n            ),\n          ),\n        ],\n      ),\n    );\n  }\n  \n  Widget _buildFloatingActionButton() {\n    final driverStatus = ref.watch(driverStatusProvider);\n    \n    return driverStatus.when(\n      data: (status) => FloatingActionButton.extended(\n        onPressed: _toggleOnlineStatus,\n        backgroundColor: status.isOnline ? Colors.red : Colors.green,\n        icon: Icon(\n          status.isOnline ? Icons.stop : Icons.play_arrow,\n          color: Colors.white,\n        ),\n        label: Text(\n          status.isOnline ? 'Desconectarse' : 'Conectarse',\n          style: const TextStyle(color: Colors.white),\n        ),\n      ).animate().scale(\n        duration: const Duration(milliseconds: 200),\n      ),\n      loading: () => const FloatingActionButton(\n        onPressed: null,\n        child: CircularProgressIndicator(strokeWidth: 2),\n      ),\n      error: (_, __) => const SizedBox.shrink(),\n    );\n  }\n  \n  void _toggleOnlineStatus() async {\n    final currentStatus = ref.read(driverStatusProvider).value;\n    if (currentStatus == null) return;\n    \n    if (!_isLocationEnabled) {\n      ScaffoldMessenger.of(context).showSnackBar(\n        const SnackBar(\n          content: Text('Necesitas habilitar la ubicación para conectarte'),\n          backgroundColor: Colors.orange,\n        ),\n      );\n      return;\n    }\n    \n    LoadingOverlay.show(context);\n    try {\n      if (currentStatus.isOnline) {\n        await ref.read(driverStatusProvider.notifier).goOffline();\n      } else {\n        await ref.read(driverStatusProvider.notifier).goOnline();\n      }\n      \n      if (mounted) {\n        LoadingOverlay.hide(context);\n      }\n    } catch (e) {\n      if (mounted) {\n        LoadingOverlay.hide(context);\n        ScaffoldMessenger.of(context).showSnackBar(\n          SnackBar(\n            content: Text('Error al cambiar estado: $e'),\n            backgroundColor: Colors.red,\n          ),\n        );\n      }\n    }\n  }\n  \n  void _centerOnCurrentLocation() {\n    if (_mapController != null && _currentLocation != null) {\n      _mapController!.animateCamera(\n        CameraUpdate.newLatLngZoom(_currentLocation!, 16),\n      );\n    }\n  }\n  \n  void _acceptRideRequest(RideRequest request) async {\n    LoadingOverlay.show(context);\n    try {\n      await ref.read(rideRequestsProvider.notifier).acceptRequest(request.id);\n      \n      if (mounted) {\n        LoadingOverlay.hide(context);\n        // Navegar a pantalla de viaje activo\n        Navigator.pushNamed(\n          context,\n          '/active-ride',\n          arguments: request.id,\n        );\n      }\n    } catch (e) {\n      if (mounted) {\n        LoadingOverlay.hide(context);\n        ScaffoldMessenger.of(context).showSnackBar(\n          SnackBar(\n            content: Text('Error al aceptar viaje: $e'),\n            backgroundColor: Colors.red,\n          ),\n        );\n      }\n    }\n  }\n  \n  void _rejectRideRequest(RideRequest request) async {\n    await ref.read(rideRequestsProvider.notifier).rejectRequest(request.id);\n  }\n  \n  void _viewRequestDetails(RideRequest request) {\n    // Mostrar detalles de la solicitud\n    showModalBottomSheet(\n      context: context,\n      isScrollControlled: true,\n      backgroundColor: Colors.transparent,\n      builder: (context) => Container(\n        height: MediaQuery.of(context).size.height * 0.7,\n        decoration: const BoxDecoration(\n          color: Colors.white,\n          borderRadius: BorderRadius.only(\n            topLeft: Radius.circular(24),\n            topRight: Radius.circular(24),\n          ),\n        ),\n        child: Column(\n          children: [\n            // Header\n            Container(\n              padding: const EdgeInsets.all(20),\n              decoration: BoxDecoration(\n                color: AppColors.primary,\n                borderRadius: const BorderRadius.only(\n                  topLeft: Radius.circular(24),\n                  topRight: Radius.circular(24),\n                ),\n              ),\n              child: Row(\n                children: [\n                  const Text(\n                    'Detalles del viaje',\n                    style: TextStyle(\n                      color: Colors.white,\n                      fontSize: 18,\n                      fontWeight: FontWeight.bold,\n                    ),\n                  ),\n                  const Spacer(),\n                  IconButton(\n                    onPressed: () => Navigator.pop(context),\n                    icon: const Icon(Icons.close, color: Colors.white),\n                  ),\n                ],\n              ),\n            ),\n            \n            // Contenido\n            Expanded(\n              child: Padding(\n                padding: const EdgeInsets.all(20),\n                child: Column(\n                  crossAxisAlignment: CrossAxisAlignment.start,\n                  children: [\n                    // Información del pasajero\n                    Text(\n                      'Pasajero: ${request.passengerName}',\n                      style: const TextStyle(\n                        fontSize: 16,\n                        fontWeight: FontWeight.bold,\n                      ),\n                    ),\n                    \n                    const SizedBox(height: 16),\n                    \n                    // Distancia y duración\n                    Row(\n                      children: [\n                        Icon(Icons.straighten, color: Colors.grey[600]),\n                        const SizedBox(width: 8),\n                        Text('${request.distance.toStringAsFixed(1)} km'),\n                        const SizedBox(width: 20),\n                        Icon(Icons.access_time, color: Colors.grey[600]),\n                        const SizedBox(width: 8),\n                        Text('${request.estimatedDuration} min'),\n                      ],\n                    ),\n                    \n                    const SizedBox(height: 16),\n                    \n                    // Tarifa estimada\n                    Container(\n                      padding: const EdgeInsets.all(16),\n                      decoration: BoxDecoration(\n                        color: Colors.green.withOpacity(0.1),\n                        borderRadius: BorderRadius.circular(8),\n                      ),\n                      child: Row(\n                        mainAxisAlignment: MainAxisAlignment.spaceBetween,\n                        children: [\n                          const Text(\n                            'Tarifa estimada:',\n                            style: TextStyle(fontWeight: FontWeight.bold),\n                          ),\n                          Text(\n                            Formatters.formatCurrency(request.estimatedFare),\n                            style: const TextStyle(\n                              fontSize: 18,\n                              fontWeight: FontWeight.bold,\n                              color: Colors.green,\n                            ),\n                          ),\n                        ],\n                      ),\n                    ),\n                    \n                    const SizedBox(height: 20),\n                    \n                    // Botones de acción\n                    Row(\n                      children: [\n                        Expanded(\n                          child: CustomButton(\n                            text: 'Rechazar',\n                            onPressed: () {\n                              Navigator.pop(context);\n                              _rejectRideRequest(request);\n                            },\n                            backgroundColor: Colors.grey[300]!,\n                            textColor: Colors.black,\n                          ),\n                        ),\n                        const SizedBox(width: 12),\n                        Expanded(\n                          child: CustomButton(\n                            text: 'Aceptar',\n                            onPressed: () {\n                              Navigator.pop(context);\n                              _acceptRideRequest(request);\n                            },\n                            backgroundColor: Colors.green,\n                          ),\n                        ),\n                      ],\n                    ),\n                  ],\n                ),\n              ),\n            ),\n          ],\n        ),\n      ),\n    );\n  }\n  \n  void _openNotifications() {\n    // Implementar panel de notificaciones\n  }\n  \n  void _openMenu() {\n    // Implementar menú lateral o modal\n  }\n  \n  void _viewEarningsDetails() {\n    // Navegar a pantalla detallada de ganancias\n    Navigator.pushNamed(context, '/earnings-details');\n  }\n}